UPDATE store_menu SET
	menu_name		= #{menuName},
	menu_description= #{menuDescription},
	menu_price		= #{menuPrice}
WHERE menu_idx		= #{menuIdx}

UPDATE store_menu SET
	display_order	= #{displayOrder}
WHERE menu_idx		= #{menuIdx}

UPDATE store_menu SET
	menu_status		= 'AVAILABLE'
WHERE menu_idx		= #{menuIdx}

UPDATE store_menu SET
	menu_status		= 'SOLD_OUT'
WHERE menu_idx		= #{menuIdx}

UPDATE store_menu SET
	member_status	= 'HIDDEN'
WHERE menu_idx		= #{menuIdx}
